  window.__AshDataInline['modules'] = {"official":[{"id":"abyss_maw","name":"深渊之喉","type":"官方战役","tags":["恐怖","地下城"],"difficulty":"高","duration":"8-12小时","players":"4-6人","desc":"一场深入地下深渊的恐怖冒险。玩家将跟随一支探险队进入特达卡西亚星的地心裂缝，面对泰坦遗骸、远古机关，以及某种比死亡更令人恐惧的存在。","region":"地心"},{"id":"purman_pass_module","name":"普尔曼隘口","type":"官方战役","tags":["政治","悬疑"],"difficulty":"中","duration":"6-10小时","players":"3-5人","desc":"围绕纳露安最著名的关隘展开的政治悬疑模组。玩家需要在人类王国与兽人帝国之间的紧张局势中寻找真相，阻止一场可能引发全面战争的阴谋。","region":"普尔曼隘口"},{"id":"twilight_of_labors","name":"十二圣工的黄昏","type":"官方战役","tags":["阴谋","角色扮演"],"difficulty":"中高","duration":"10-16小时","players":"4-5人","desc":"奥弗丹教权内部的权力斗争。玩家扮演被卷入教廷阴谋的外来者，需要在信仰与生存之间做出选择。","region":"奥弗丹"},{"id":"shrimp_song","name":"海涯鼓虾之歌","type":"官方战役","tags":["海洋","探险"],"difficulty":"中","duration":"6-8小时","players":"3-6人","desc":"以安温提沿海为舞台的海洋冒险。玩家将驾驶帆船探索未知海域，与巨型鼓虾打交道，揭开被潮汐掩埋的古老秘密。","region":"安温提"}],"short":[{"id":"last_tavern","name":"最后一家酒馆","type":"短篇","tags":["温馨","短篇"],"difficulty":"低","duration":"2-3小时","source":"社区精选","desc":"浩劫后的世界中，一家神秘酒馆成为旅人的避风港。玩家需要在一晚之内解开酒馆主人的秘密。"},{"id":"winter_hunt","name":"冬猎","type":"短篇","tags":["狩猎","冰霜"],"difficulty":"中","duration":"3-4小时","source":"官方","desc":"芬恩莱特北方的冬季狩猎。一场看似简单的猎狼任务逐渐演变为与远古冰霜生物的遭遇战。","region":"芬恩莱特"},{"id":"spider_dowry","name":"蜘蛛的嫁妆","type":"短篇","tags":["外交","蛛灵"],"difficulty":"中","duration":"4-5小时","source":"官方","desc":"蛛灵社会的入门模组。玩家以人类商人的身份进入蛛灵领地，参与一场危险的联姻谈判。","related_race":"蛛灵"},{"id":"moji_night","name":"莫季之夜","type":"短篇","tags":["仪式","牛头人"],"difficulty":"中高","duration":"4-6小时","source":"官方","desc":"在只有一个月的季节交替期，牛头人部落举行拒绝承认莫季的仪式。玩家被邀请参加，却发现仪式背后隐藏着古老的诅咒。","related_race":"牛头人"}]};
